def parse_nested_parens(paren_string: str) -> List[int]:
    def dfs(s: str, depth: int, max_depth: List[int]) -> None:
        if not s:
            return
        if s[0] == '(':
            max_depth[0] = max(max_depth[0], depth)
            dfs(s[1:], depth + 1, max_depth)
        elif s[0] == ')':
            dfs(s[1:], depth - 1, max_depth)

    groups = paren_string.split()
    result = []
    for group in groups:
        max_depth = [1]
        dfs(group, 1, max_depth)
        result.append(max_depth[0])
    return result

