def make_palindrome(string: str) -> str:
    n = len(string)
    for i in range(n):
        left, right = i, n - 1
        while left < right and string[left] == string[right]:
            left += 1
            right -= 1

        if left >= right:
            prefix = string[:i]
            return string + prefix[::-1]

    return string

