def find_closest_elements(numbers: List[float]) -> Tuple[float, float]:
    numbers.sort()
    min_diff = float('inf')
    closest_pair = (0, 0)

    left, right = 0, len(numbers) - 1

    while left < right:
        diff = numbers[right] - numbers[left]
        if diff < min_diff:
            min_diff = diff
            closest_pair = (numbers[left], numbers[right])

        if diff == 0:
            return closest_pair

        if numbers[right] - numbers[left + 1] < numbers[left + 2] - numbers[right]:
            left += 1
        else:
            right -= 1

    return closest_pair

