def find_zero(xs: list):
    def poly(coeffs, x):
        return sum(coeff * math.pow(x, i) for i, coeff in enumerate(coeffs))

    if len(xs) % 2 != 0:
        raise ValueError("Polynomial must have an even number of coefficients")

    a = -1.0
    b = 1.0

    while poly(xs, a) * poly(xs, b) > 0:
        a *= 2
        b *= 2

    while (b - a) / 2 > 1e-10:
        c = (a + b) / 2
        if poly(xs, c) == 0:
            return c
        elif poly(xs, a) * poly(xs, c) < 0:
            b = c
        else:
            a = c

    return (a + b) / 2

